const fs = require('fs');

const sourcePath = '/home/node/analysis/top50.csv';
const outputPath = '/files/workflows/demo/staging_output.csv';

function splitCsvLine(line) {
  const cells = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i += 1) {
    const char = line[i];

    if (char === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (char === ',' && !inQuotes) {
      cells.push(current);
      current = '';
      continue;
    }

    current += char;
  }

  cells.push(current);
  return cells;
}

function parseCsv(text) {
  const normalized = text.replace(/^\uFEFF/, '').trim();
  const lines = normalized.split(/\r?\n/).filter((line) => line.trim().length > 0);
  if (lines.length < 2) {
    throw new Error('WF-1 expected CSV headers and data rows');
  }

  const headers = splitCsvLine(lines[0]).map((header) => header.trim());
  return lines.slice(1).map((line) => {
    const values = splitCsvLine(line);
    const row = {};
    headers.forEach((header, index) => {
      row[header] = values[index] ?? '';
    });
    return row;
  });
}

function escapeCsv(value) {
  const text = value === null || value === undefined ? '' : String(value);
  return /[",\n\r]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
}

const rows = parseCsv(fs.readFileSync(sourcePath, 'utf8'));
const tierA = rows.filter((row) => String(row.tier).trim().toUpperCase() === 'A');
const tierB = rows.filter((row) => String(row.tier).trim().toUpperCase() === 'B');

if (rows.length !== 50) {
  throw new Error(`WF-1 expected 50 rows in analysis/top50.csv, got ${rows.length}`);
}
if (tierA.length !== 15) {
  throw new Error(`WF-1 expected 15 Tier A rows, got ${tierA.length}`);
}
if (tierB.length !== 35) {
  throw new Error(`WF-1 expected 35 Tier B rows, got ${tierB.length}`);
}

const headers = [
  'rank',
  'brand_id',
  'tier',
  'category',
  'gmv_cop_millions_12m',
  'n_unique_clients_12m',
  'gmv_90d_to_12m_ratio',
  'days_since_last_orig',
  'recency_score',
  'fit_score',
  'momentum_score',
  'category_bonus',
  'final_score',
  'why',
  'routing'
];

const csv = [
  headers.join(','),
  ...rows.map((row) => headers.map((header) => escapeCsv(row[header])).join(','))
].join('\n') + '\n';

fs.mkdirSync('/files/workflows/demo', { recursive: true });
fs.writeFileSync(outputPath, csv, 'utf8');

return [
  {
    json: {
      timestamp: new Date().toISOString(),
      source_path: sourcePath,
      output_path: outputPath,
      total_rows: rows.length,
      tier_a_count: tierA.length,
      tier_b_count: tierB.length
    }
  }
];
